// Custom error handler overriding grpc-gateway's default status mapping
mux := runtime.NewServeMux(
    runtime.WithErrorHandler(func(ctx context.Context, mux *runtime.ServeMux,
        m runtime.Marshaler, w http.ResponseWriter, r *http.Request, err error) {
        s := status.Convert(err)
        switch s.Code() {
        case codes.NotFound:
            w.WriteHeader(http.StatusNotFound) // 404
        case codes.AlreadyExists:
            w.WriteHeader(http.StatusConflict) // 409
        case codes.InvalidArgument:
            w.WriteHeader(http.StatusBadRequest) // 400
        default:
            runtime.DefaultHTTPErrorHandler(ctx, mux, m, w, r, err)
        }
    }),
)

// user.proto
syntax = "proto3";

service UserService {
  rpc GetUser (GetUserRequest) returns (User);                          // unary
  rpc WatchUserActivity (WatchRequest) returns (stream ActivityEvent); // server stream
  rpc UploadAvatar (stream Chunk) returns (UploadResult);             // client stream
  rpc Chat (stream ChatMessage) returns (stream ChatMessage);         // bidi stream
}

message GetUserRequest { string user_id = 1; }
message User { string user_id = 1; string name = 2; int64 created_at = 3; }
message ActivityEvent { string event_type = 1; int64 timestamp = 2; }
message Chunk { bytes data = 1; }
message UploadResult { string url = 1; }
message ChatMessage { string sender_id = 1; string text = 2; }

// pagination.proto
message ListBytesRequest {
  string page_token = 1;  // opaque cursor, empty = first page
  int32  page_size  = 2;  // max 100, default 20
  bool   request_total = 3; // opt-in: triggers COUNT(*)
}

message ListBytesResponse {
  repeated Byte bytes          = 1;
  string        next_page_token = 2; // empty = last page
  optional int64 total_count   = 3; // only set if request_total=true
}

service ByteService {
  rpc ListBytes(ListBytesRequest) returns (ListBytesResponse);
}

