var limiters sync.Map

func RateLimitInterceptor(ctx context.Context, req any, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (any, error) {
	md, _ := metadata.FromIncomingContext(ctx)
	uids := md.Get("x-user-id")
	if len(uids) == 0 {
		return nil, status.Error(codes.Unauthenticated, "missing user id")
	}
	key := uids[0] + ":" + info.FullMethod
	v, _ := limiters.LoadOrStore(key, rate.NewLimiter(rate.Every(time.Second), 10))
	if !v.(*rate.Limiter).Allow() {
		grpc.SetTrailer(ctx, metadata.Pairs("retry-after", "1s"))
		return nil, status.Error(codes.ResourceExhausted, "rate limit exceeded")
	}
	return handler(ctx, req)
}

import (
    "google.golang.org/grpc"
    "google.golang.org/grpc/codes"
    "google.golang.org/grpc/metadata"
    "google.golang.org/grpc/status"
    // Do NOT import: "google.golang.org/grpc/reflection" in prod
)

func ValidationInterceptor(ctx context.Context, req any, _ *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (any, error) {
    md, ok := metadata.FromIncomingContext(ctx)
    if !ok {
        return nil, status.Error(codes.InvalidArgument, "missing metadata")
    }
    if vals := md.Get("x-forwarded-for"); len(vals) > 0 {
        return nil, status.Error(codes.PermissionDenied, "untrusted hop header rejected")
    }
    return handler(ctx, req)
}

// Server setup — cap payload, skip reflection registration
grpc.NewServer(
    grpc.MaxRecvMsgSize(1<<20), // 1 MB
    grpc.UnaryInterceptor(ValidationInterceptor),
)

func problemJSONErrorHandler(ctx context.Context, mux *runtime.ServeMux,
	m runtime.Marshaler, w http.ResponseWriter, r *http.Request, err error) {

	s := status.Convert(err)
	w.Header().Set("Content-Type", "application/problem+json")
	w.WriteHeader(runtime.HTTPStatusFromCode(s.Code()))

	json.NewEncoder(w).Encode(map[string]any{
		"type":   fmt.Sprintf("https://api.example.com/errors/%s", s.Code()),
		"title":  s.Code().String(),
		"status": runtime.HTTPStatusFromCode(s.Code()),
		"detail": s.Message(),
	})
}

// Wire it up
mux := runtime.NewServeMux(
	runtime.WithErrorHandler(problemJSONErrorHandler),
)

